import React, { useState } from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faCommentDots, faBars, faXmark } from '@fortawesome/free-solid-svg-icons';
import '../styles/Navbar.css';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import { APP_NAME, COMPANY_NAME } from '../appFiles/shared/utility';
import { isMobile } from 'react-device-detect';

function Navbar() {
	const [nav, setNav] = useState(false);
	const [isButtonDisabled, setIsButtonDisabled] = useState(false);

	const openNav = () => {
		setNav(!nav);
	};

	const handleChatBtnClick = () => {
		if (!isButtonDisabled) {
			toast.info('Experiencing high traffic, Please wait a moment.', {
				position: toast.POSITION.TOP_CENTER,
				onOpen: () => setIsButtonDisabled(true),
				onClose: () => setIsButtonDisabled(false),
			});
		}
	};

	return (
		<div className="navbar-section">
			<h1 className="navbar-title" style={{fontSize: isMobile ? '22px': ''}}>
				<Link to="/">
					{COMPANY_NAME}
				</Link>
			</h1>

			{/* Desktop */}
			<ul className="navbar-items">
				<li>
					<Link to="/" className="navbar-links">
						{`Home`}
					</Link>
				</li>
				<li>
					<a href="#/flowhero" className="navbar-links">
						{APP_NAME}
					</a>
				</li>
				<li>
					<a href="#/register" className="navbar-links">
						{`Register`}
					</a>
				</li>
			</ul>

			<button className="navbar-btn" type="button" disabled={isButtonDisabled} onClick={handleChatBtnClick}>
				<FontAwesomeIcon icon={faCommentDots} /> Live Chat
			</button>

			{/* Mobile */}
			<div className={`mobile-navbar ${nav ? 'open-nav' : ''}`}>
				<div onClick={openNav} className="mobile-navbar-close">
					<FontAwesomeIcon icon={faXmark} className="hamb-icon" />
				</div>

				<ul className="mobile-navbar-links">
					<li>
						<Link onClick={openNav} to="/">
							Home
						</Link>
					</li>
					
					
					
					<li>
						<a onClick={openNav} href="/#/flowhero">
							{APP_NAME}
						</a>
					</li>
					
				</ul>
			</div>

			{/* Hamburger Icon */}
			<div className="mobile-nav">
				<FontAwesomeIcon icon={faBars} onClick={openNav} className="hamb-icon" />
			</div>
		</div>
	);
}

export default Navbar;
